/**
 * Nakshatra Pada Profiles — 108 entries (27 nakshatras x 4 padas)
 *
 * Each pada maps to a navamsha sign that colors the interpretation.
 * The navamsha cycle repeats every 3 nakshatras (12 signs / 4 padas per nakshatra = 3).
 * Syllables follow the Kaatyayana tradition (sourced from NAKSHATRA_SYLLABLES).
 */

export interface NakshatraPadaProfile {
  nakshatraId: number;     // 1-27
  pada: number;            // 1-4
  navamshaSign: number;    // 1-12 (Aries=1 through Pisces=12)
  syllable: string;        // Starting syllable for baby names (Latin script)
  personality: { en: string; hi: string };
  career: { en: string; hi: string };
  relationships: { en: string; hi: string };
  health: { en: string; hi: string };
  deity: string;
  element: string;         // Element of the navamsha sign: Fire/Earth/Air/Water
  keywords: string[];
}

