/**
 * Compute navamsha sign for a given nakshatra + pada.
 * Pattern: Each nakshatra's pada 1 starts at ((nakshatraId-1)*4) % 12 + 1,
 * incrementing by 1 for each subsequent pada.
 */
function navamshaForPada(nakshatraId: number, pada: number): number {
  return ((nakshatraId - 1) * 4 + (pada - 1)) % 12 + 1;
}

