// ────────────────────────────────────────────────────────────
// Lookup helpers
// ────────────────────────────────────────────────────────────

/** Get a specific pada profile by nakshatra ID (1-27) and pada (1-4) */
export function getPadaProfile(nakshatraId: number, pada: number): NakshatraPadaProfile | undefined {
  return NAKSHATRA_PADA_PROFILES.find(p => p.nakshatraId === nakshatraId && p.pada === pada);
}

/** Get all 4 pada profiles for a given nakshatra */
export function getProfilesByNakshatra(nakshatraId: number): NakshatraPadaProfile[] {
  return NAKSHATRA_PADA_PROFILES.filter(p => p.nakshatraId === nakshatraId);
}

/** Find a pada profile by its baby-name syllable (case-insensitive) */
export function findPadaBySyllable(syllable: string): NakshatraPadaProfile | undefined {
  const lower = syllable.toLowerCase();
  return NAKSHATRA_PADA_PROFILES.find(p => p.syllable.toLowerCase() === lower);
}

/** Get all padas that share a given navamsha sign (1-12) */
export function getProfilesByNavamsha(navamshaSign: number): NakshatraPadaProfile[] {
  return NAKSHATRA_PADA_PROFILES.filter(p => p.navamshaSign === navamshaSign);
}

/** Build slug from nakshatra ID and pada */
export function buildPadaSlug(nakshatraId: number, pada: number): string {
  return `${NAKSHATRA_SLUGS[nakshatraId]}-pada-${pada}`;
}

/** Parse a slug like "ashwini-pada-1" into { nakshatraId, pada } */
export function parsePadaSlug(slug: string): { nakshatraId: number; pada: number } | null {
  const match = slug.match(/^(.+)-pada-(\d)$/);
  if (!match) return null;
  const nakshatraSlug = match[1];
  const pada = parseInt(match[2], 10);
  if (pada < 1 || pada > 4) return null;
  const nakshatraId = NAKSHATRA_SLUGS.indexOf(nakshatraSlug);
  if (nakshatraId < 1) return null;
  return { nakshatraId, pada };
}
